insert into public.facilities
  (id, name, org, type, cc, city, lat, lng, sectors, capabilities, access, equipment, blurb, website, status)
values
  ('DE-010', 'Fraunhofer IISB – SiC Power Electronics & Crystal Growth', 'Fraunhofer Institute for Integrated Systems and Device Technology IISB', 'Pilot Line / Test Bed', 'DE', 'Erlangen', 49.571, 11.027, ARRAY['Semiconductors & Photonics','Advanced Materials','Energy & Climate']::text[], ARRAY['Cleanroom / Nanofab','Pilot Line / Scale-up','Characterization & Metrology']::text[], 'Collaboration / contract R&D', '150 mm SiC line, AlN PVT crystal growth, power device & module assembly, 1,300 m2 cleanroom', 'Through its ''SiC Services'', IISB offers external industry customers contract R&D on a 150 mm SiC line, from material development to SiC power-device prototypes and module assembly.', 'iisb.fraunhofer.de', 'approved'),
  ('DE-011', 'Fraunhofer IAF – GaN Foundry & MPW Service', 'Fraunhofer Institute for Applied Solid State Physics IAF', 'Pilot Line / Test Bed', 'DE', 'Freiburg', 48.003, 7.829, ARRAY['Semiconductors & Photonics','Quantum']::text[], ARRAY['Cleanroom / Nanofab','Pilot Line / Scale-up','Characterization & Metrology']::text[], 'Fee-for-service', 'GaN HEMT process family, multi-project wafer runs, full mask processing, mmW measurement up to 200 GHz', 'IAF gives industry and science partners access to its GaN high-frequency process family via multi-project wafer (MPW) runs and full mask processing, including small-series production.', 'iaf.fraunhofer.de', 'approved'),
  ('DE-012', 'Ferdinand-Braun-Institut (FBH) – III-V Foundry & Diode Laser Service', 'Leibniz-Institut fur Hochstfrequenztechnik (FBH)', 'Core Facility', 'DE', 'Berlin', 52.431, 13.531, ARRAY['Semiconductors & Photonics','Quantum']::text[], ARRAY['Cleanroom / Nanofab','Pilot Line / Scale-up','Characterization & Metrology']::text[], 'Collaboration / contract R&D', '2-4 inch GaAs/GaN process line, gas-phase epitaxy, high-power diode laser fabrication, MMIC pilot series', 'For customers in industry and science, FBH provides prototyping and pilot series of GaAs/GaN devices, MMICs and high-power diode lasers from its industry-compatible clean-room labs.', 'fbh-berlin.de', 'approved'),
  ('DE-013', 'Fraunhofer IPMS – Quantum Foundry & 300 mm Cleanroom', 'Fraunhofer Institute for Photonic Microsystems IPMS', 'Pilot Line / Test Bed', 'DE', 'Dresden', 51.029, 13.757, ARRAY['Quantum','Semiconductors & Photonics']::text[], ARRAY['Cleanroom / Nanofab','Pilot Line / Scale-up','Characterization & Metrology']::text[], 'Open user access (proposal)', '300 mm R&D cleanroom, MEMS/quantum process development, multi-project wafers, quantum PDKs', 'Via the EU SPINS/SUPREME quantum pilot lines, IPMS opens its 300 mm Quantum Foundry to startups and SMEs through multi-project wafers and standardized quantum process design kits.', 'ipms.fraunhofer.de', 'approved'),
  ('DE-014', 'Fraunhofer ISIT – MEMS Pilot Production', 'Fraunhofer Institute for Silicon Technology ISIT', 'Pilot Line / Test Bed', 'DE', 'Itzehoe', 53.922, 9.515, ARRAY['Semiconductors & Photonics','Advanced Manufacturing']::text[], ARRAY['Cleanroom / Nanofab','Pilot Line / Scale-up']::text[], 'Fee-for-service', '200 mm Si line, dedicated MEMS/NEMS & packaging cleanroom, pilot production 10-5,000 wafers/yr', 'ISIT manufactures customer devices to specification at pilot scale and, with the co-located X-FAB MEMS foundry, bridges prototypes to industrial volume production.', 'isit.fraunhofer.de', 'approved'),
  ('DE-015', 'Fraunhofer IOF – Optics & Photonics Manufacturing', 'Fraunhofer Institute for Applied Optics and Precision Engineering IOF', 'Research Institute', 'DE', 'Jena', 50.909, 11.589, ARRAY['Semiconductors & Photonics','Advanced Manufacturing','Space & Aerospace']::text[], ARRAY['Pilot Line / Scale-up','Characterization & Metrology','Prototyping / Makerspace']::text[], 'Collaboration / contract R&D', 'Ultra-precision machining, optical coating, diamond turning, micro/nano-optics, 3D metrology', 'IOF performs contract R&D along the full photonic chain, from design and coatings to ultra-precision manufacturing, prototypes and pilot series for companies of all sizes.', 'iof.fraunhofer.de', 'approved'),
  ('DE-016', 'Fraunhofer ILT – Laser Technology Contract R&D', 'Fraunhofer Institute for Laser Technology ILT', 'Research Institute', 'DE', 'Aachen', 50.779, 6.083, ARRAY['Advanced Manufacturing','Semiconductors & Photonics','Advanced Materials']::text[], ARRAY['Prototyping / Makerspace','Pilot Line / Scale-up','Characterization & Metrology']::text[], 'Collaboration / contract R&D', 'Laser materials processing, laser-based optics manufacturing, additive manufacturing, in-line metrology', 'One of the world''s leading laser contract-R&D institutes, ILT runs projects for industry customers from public-private partnerships to fully confidential contract research, including prototypes and small series.', 'ilt.fraunhofer.de', 'approved'),
  ('DE-017', 'Fraunhofer IWS – Laser & Additive Manufacturing (AMCD)', 'Fraunhofer Institute for Material and Beam Technology IWS', 'Research Institute', 'DE', 'Dresden', 51.029, 13.761, ARRAY['Advanced Manufacturing','Advanced Materials']::text[], ARRAY['Prototyping / Makerspace','Pilot Line / Scale-up','Characterization & Metrology']::text[], 'Collaboration / contract R&D', 'Laser cladding, LPBF & EBM additive manufacturing, thermal spray, laser hardening', 'IWS develops customized laser, coating and additive-manufacturing solutions on contract for industry, with the Additive Manufacturing Center Dresden (AMCD) open as a joint competence center.', 'iws.fraunhofer.de', 'approved'),
  ('DE-018', 'Fraunhofer IFAM – Manufacturing & Materials Center', 'Fraunhofer Institute for Manufacturing Technology and Advanced Materials IFAM', 'Research Institute', 'DE', 'Bremen', 53.118, 8.642, ARRAY['Advanced Materials','Advanced Manufacturing','Robotics & Automation']::text[], ARRAY['Pilot Line / Scale-up','Prototyping / Makerspace','Characterization & Metrology']::text[], 'Collaboration / contract R&D', 'PBF-LB & binder-jetting additive manufacturing, adhesive-bonding tech center, 4,000 m2 robotics research hall', 'IFAM offers contract research across adhesive bonding, functional materials and additive manufacturing, plus a large research hall where companies validate processes at 1:1 scale with robots and metrology.', 'ifam.fraunhofer.de', 'approved'),
  ('DE-019', 'Fraunhofer IPT – Production Technology & ICNAP', 'Fraunhofer Institute for Production Technology IPT', 'Pilot Line / Test Bed', 'DE', 'Aachen', 50.782, 6.051, ARRAY['Advanced Manufacturing','Robotics & Automation']::text[], ARRAY['Pilot Line / Scale-up','Prototyping / Makerspace','Characterization & Metrology']::text[], 'Collaboration / contract R&D', '5,000 m2 labs, ultra-precision machines, roll-to-roll systems, production metrology, ICNAP test environment', 'IPT builds individual prototypes, pilot and demonstration lines for partners and runs the open ICNAP industrial test platform for networked, adaptive production.', 'ipt.fraunhofer.de', 'approved'),
  ('DE-020', 'Fraunhofer IPA – Robotics & AI Testing Facility', 'Fraunhofer Institute for Manufacturing Engineering and Automation IPA', 'Pilot Line / Test Bed', 'DE', 'Stuttgart', 48.74, 9.098, ARRAY['Robotics & Automation','Advanced Manufacturing']::text[], ARRAY['Prototyping / Makerspace','Characterization & Metrology']::text[], 'Collaboration / contract R&D', '~20 industrial robots, AI & robotics test center, 40,000 m2 of test environments, lab-automation center', 'IPA acts as a neutral partner offering companies feasibility studies, tests and prototyping in robotics labs and a Test Center for AI & Robotics that recreates realistic production scenarios.', 'ipa.fraunhofer.de', 'approved'),
  ('DE-021', 'Fraunhofer IKTS – Ceramics Pilot Plant', 'Fraunhofer Institute for Ceramic Technologies and Systems IKTS', 'Pilot Line / Test Bed', 'DE', 'Dresden', 51.003, 13.792, ARRAY['Advanced Materials','Energy & Climate']::text[], ARRAY['Pilot Line / Scale-up','Characterization & Metrology','Prototyping / Makerspace']::text[], 'Collaboration / contract R&D', 'High-performance ceramic processing lines, materials diagnostics, non-destructive testing, pilot-plant scale-up', 'As Europe''s largest ceramics R&D institute, IKTS makes industrially-suited equipment available to partners and customers to realize prototypes and pilot-production series for market launch.', 'ikts.fraunhofer.de', 'approved'),
  ('DE-022', 'Fraunhofer FFB – PreFab Open Battery Cell Factory', 'Fraunhofer Research Institution for Battery Cell Production FFB', 'Pilot Line / Test Bed', 'DE', 'Munster', 51.997, 7.586, ARRAY['Energy & Climate','Advanced Materials','Advanced Manufacturing']::text[], ARRAY['Pilot Line / Scale-up','Characterization & Metrology']::text[], 'Fee-for-service', 'Integrated cell pilot line: electrode manufacturing, cell assembly, formation; pouch-cell production', 'FFB PreFab is an open battery-cell factory where companies from SMEs to large corporates test and scale new cell chemistries and production equipment approaching series production.', 'ffb.fraunhofer.de', 'approved'),
  ('DE-023', 'ZSW – eLaB Battery Research Production Line', 'Zentrum fur Sonnenenergie- und Wasserstoff-Forschung (ZSW)', 'Pilot Line / Test Bed', 'DE', 'Ulm', 48.425, 9.956, ARRAY['Energy & Climate','Advanced Materials']::text[], ARRAY['Pilot Line / Scale-up','Characterization & Metrology']::text[], 'Collaboration / contract R&D', 'Research production line for large Li-ion cells, ''Powder-Up!'' materials pilot plant, water-based electrode line', 'ZSW''s eLaB offers a manufacturer-independent research platform where industry partners develop and scale battery cell and materials production processes.', 'zsw-bw.de', 'approved'),
  ('DE-024', 'Fraunhofer ISE – PV-TEC & Hydrogen Pilot Plants', 'Fraunhofer Institute for Solar Energy Systems ISE', 'Pilot Line / Test Bed', 'DE', 'Freiburg', 48.014, 7.832, ARRAY['Energy & Climate','Semiconductors & Photonics','Advanced Materials']::text[], ARRAY['Pilot Line / Scale-up','Characterization & Metrology']::text[], 'Fee-for-service', 'PV-TEC solar-cell line (TOPCon), screen-printing & metallization, fuel-cell/electrolyzer MEA pilot plants, accredited TestLab PV', 'ISE supports companies across the PV value chain at its PV-TEC pilot line and runs industrial-scale fuel-cell and electrolyzer MEA pilot plants for partners developing hydrogen components.', 'ise.fraunhofer.de', 'approved'),
  ('DE-025', 'Fraunhofer IZI – GMP Cell & Gene Therapy Manufacturing', 'Fraunhofer Institute for Cell Therapy and Immunology IZI', 'Core Facility', 'DE', 'Leipzig', 51.314, 12.397, ARRAY['Life Sciences & Biotech']::text[], ARRAY['Biomanufacturing / GMP','Wet Lab','Characterization & Metrology']::text[], 'Collaboration / contract R&D', 'Two GMP facilities, 6 clean-room suites, 13 grade-B manufacturing rooms, CAR-T/AAV/antibody production', 'IZI offers GMP-compliant contract manufacturing and process development of advanced therapies (CAR-T, viral vectors, antibodies) for industrial and academic clients.', 'izi.fraunhofer.de', 'approved'),
  ('DE-026', 'IZB – Innovation & Start-up Center Biotechnology', 'Fordergesellschaft IZB mbH', 'Incubator / Accelerator', 'DE', 'Planegg-Martinsried', 48.106, 11.464, ARRAY['Life Sciences & Biotech']::text[], ARRAY['Wet Lab','Dry Lab']::text[], 'Membership / residency', 'Furnished S1 laboratory units, office space, shared infrastructure on the Martinsried life-science campus', 'IZB rents furnished S1 wet-lab and office units to biotech start-ups on the Martinsried/Weihenstephan campuses, hosting 40+ companies with financing and network support.', 'izb-online.de', 'approved'),
  ('DE-027', 'BioPark Regensburg', 'BioPark Regensburg GmbH', 'Incubator / Accelerator', 'DE', 'Regensburg', 48.999, 12.095, ARRAY['Life Sciences & Biotech']::text[], ARRAY['Wet Lab','Dry Lab']::text[], 'Membership / residency', '~5,400 m2 of laboratory space across three buildings, flexible office-laboratory combinations, shared services', 'BioPark Regensburg leases wet-lab and office space to biotech, medtech and diagnostics startups under a flexible concept on the University of Regensburg grounds.', 'biopark-regensburg.de', 'approved'),
  ('DE-028', 'ZARM – Bremen Drop Tower', 'Center of Applied Space Technology and Microgravity (ZARM)', 'Core Facility', 'DE', 'Bremen', 53.102, 8.853, ARRAY['Space & Aerospace','Advanced Materials']::text[], ARRAY['Characterization & Metrology','Launchpad - Space']::text[], 'Open user access (proposal)', '146 m drop tower, catapult system, GraviTower, payload capsules, experiment-integration support', 'The Bremen Drop Tower is an open microgravity laboratory where external researchers and companies book two-week campaigns (drops, catapults, GraviTower) with full ZARM engineering support.', 'zarm.uni-bremen.de', 'approved'),
  ('DE-029', 'ESA BIC Bavaria & Northern Germany', 'AZO GmbH / ESA', 'Incubator / Accelerator', 'DE', 'Oberpfaffenhofen', 48.084, 11.281, ARRAY['Space & Aerospace','Robotics & Automation']::text[], ARRAY['Prototyping / Makerspace']::text[], 'Program / cohort', 'Incubation grants, mentoring, access to ESA technology and partner R&D facilities', 'ESA BIC runs a cohort incubation programme for space and space-tech startups, providing funding, mentoring and access to ESA and partner R&D facilities; ESA BIC Bavaria has supported 230+ startups.', 'esa-bic.de', 'approved'),
  ('DE-030', 'ZAL TechCenter – Applied Aeronautical Research', 'ZAL Zentrum fur Angewandte Luftfahrtforschung GmbH', 'Pilot Line / Test Bed', 'DE', 'Hamburg', 53.536, 9.976, ARRAY['Space & Aerospace','Advanced Manufacturing']::text[], ARRAY['Prototyping / Makerspace','Characterization & Metrology']::text[], 'Membership / residency', 'Aerospace acoustics chamber, additive manufacturing, hydrogen test labs, test rigs & full-size mock-ups, AI lab', 'ZAL provides aviation test infrastructure (acoustics, hydrogen, additive manufacturing, test rigs) and ~850 workspaces that SMEs and technology partners rent for project-based research.', 'zal.aero', 'approved'),
  ('BE-001', 'imec.IC-link (MPW prototyping & ASIC/PIC fabrication)', 'imec', 'Pilot Line / Test Bed', 'BE', 'Leuven', 50.8625, 4.6803, ARRAY['Semiconductors & Photonics','Quantum']::text[], ARRAY['Cleanroom / Nanofab','Pilot Line / Scale-up','Prototyping / Makerspace']::text[], 'Fee-for-service', 'Multi-project-wafer runs, ASIC/GaN fabrication, ISiPP50G silicon-photonics PIC prototyping, small-volume production', 'imec.IC-link offers companies of any size, from startups to large firms, affordable chip prototyping via shared multi-project-wafer runs and small-volume ASIC and silicon-photonics fabrication.', 'imeciclink.com', 'approved'),
  ('BE-002', 'imec NanoIC Pilot Line', 'imec', 'Pilot Line / Test Bed', 'BE', 'Leuven', 50.8625, 4.6803, ARRAY['Semiconductors & Photonics','Quantum']::text[], ARRAY['Cleanroom / Nanofab','Pilot Line / Scale-up','Characterization & Metrology']::text[], 'Open user access (proposal)', '300mm sub-2nm cleanroom (12,000+ m2), High-NA EUV lithography, advanced SoC process baselines, PDKs', 'Launched under the EU Chips Act, the NanoIC pilot line gives startups, SMEs, universities and design companies early access to sub-2nm prototyping, design exploration and PDKs alongside foundries.', 'nanoic-project.eu', 'approved'),
  ('BE-003', 'imec.istart', 'imec', 'Incubator / Accelerator', 'BE', 'Ghent', 51.0259, 3.7174, ARRAY['Semiconductors & Photonics','Advanced Manufacturing','Robotics & Automation']::text[], ARRAY['Prototyping / Makerspace','Dry Lab']::text[], 'Program / cohort', '', 'imec.istart is an open tech-startup accelerator offering selected teams 12-18 months of mentoring, pre-seed funding and access to imec technology and facilities, operating from Ghent, Antwerp, Hasselt and Liege.', 'imecistart.com', 'approved'),
  ('BE-004', 'EnergyVille', 'KU Leuven / VITO / imec / UHasselt', 'Core Facility', 'BE', 'Genk', 50.993, 5.534, ARRAY['Energy & Climate','Advanced Materials','Semiconductors & Photonics']::text[], ARRAY['Dry Lab','Characterization & Metrology','Pilot Line / Scale-up']::text[], 'Fee-for-service', 'Battery testing lab, battery dry room, PV reliability lab, power-electronics labs, Open Thor living lab', 'EnergyVille''s energy-research labs in Genk (battery, PV reliability, power electronics) can be rented in part by companies under supervision to test and optimise materials, components and systems.', 'energyville.be', 'approved'),
  ('BE-005', 'Flanders Make', 'Flanders Make', 'Pilot Line / Test Bed', 'BE', 'Lommel', 51.2306, 5.3142, ARRAY['Advanced Manufacturing','Robotics & Automation']::text[], ARRAY['Pilot Line / Scale-up','Prototyping / Makerspace','Characterization & Metrology']::text[], 'Collaboration / contract R&D', 'Make Lab mobile testbed, AI/mechatronics & robotics demonstrators, human-robot cobot living labs, validation rigs', 'Flanders Make opens its test and validation infrastructure (robotics, mechatronics, vehicle and production demonstrators) to manufacturing companies, especially SMEs, across sites in Lommel, Leuven and Kortrijk.', 'flandersmake.be', 'approved'),
  ('BE-006', 'Sirris Industrial Labs', 'Sirris', 'Core Facility', 'BE', 'Brussels', 50.8718, 4.4023, ARRAY['Advanced Manufacturing','Robotics & Automation','Advanced Materials']::text[], ARRAY['Prototyping / Makerspace','Pilot Line / Scale-up','Characterization & Metrology']::text[], 'Fee-for-service', 'Metal/polymer/ceramic additive manufacturing, 5-axis precision milling, femtosecond laser texturing, microfabrication, accredited test labs', 'Sirris, the collective centre of the Belgian tech industry, offers companies fee-based access to additive-manufacturing, precision-machining, microfabrication, robotics and accredited materials-testing infrastructure across 8 sites.', 'sirris.be', 'approved'),
  ('BE-007', 'von Karman Institute for Fluid Dynamics', 'von Karman Institute', 'Core Facility', 'BE', 'Sint-Genesius-Rode', 50.743, 4.359, ARRAY['Space & Aerospace','Energy & Climate','Advanced Manufacturing']::text[], ARRAY['Characterization & Metrology','Pilot Line / Scale-up']::text[], 'Collaboration / contract R&D', '~50 wind tunnels (up to Mach 14), Plasmatron, compression tube, turbomachinery, aeroacoustic rigs', 'VKI runs about fifty wind tunnels and specialised fluid-dynamics test facilities, performing experimental research and consultancy for aerospace, automotive, energy and environmental industry clients.', 'vki.ac.be', 'approved'),
  ('BE-008', 'SCK CEN (Belgian Nuclear Research Centre)', 'SCK CEN', 'Core Facility', 'BE', 'Mol', 51.216, 5.095, ARRAY['Energy & Climate','Advanced Materials','Life Sciences & Biotech']::text[], ARRAY['Characterization & Metrology','Pilot Line / Scale-up']::text[], 'Open user access (proposal)', 'BR2 high-flux material test reactor, gamma irradiation facilities, hot cells, radiochemical labs, dosimetry services', 'As an IAEA-designated international reactor centre, SCK CEN in Mol opens its BR2 reactor, irradiation, hot-cell and radiochemical facilities to external users and offers tailor-made irradiation and dosimetry services.', 'sckcen.be', 'approved'),
  ('BE-009', 'CRM Group', 'CRM Group', 'Pilot Line / Test Bed', 'BE', 'Liege', 50.587, 5.564, ARRAY['Advanced Materials','Energy & Climate','Advanced Manufacturing']::text[], ARRAY['Pilot Line / Scale-up','Characterization & Metrology']::text[], 'Collaboration / contract R&D', 'Metallurgy pilot & semi-industrial lines, ISO 7 cleanroom roll-to-roll / slot-die coating line, metals test facilities', 'CRM Group provides metallurgy R&D and pilot- to semi-industrial-scale process lines (including a roll-to-roll cleanroom coating line) for contract research and bilateral industry partnerships.', 'crmgroup.be', 'approved'),
  ('BE-010', 'Materia Nova', 'Materia Nova / UMONS', 'Research Institute', 'BE', 'Mons', 50.454, 3.956, ARRAY['Advanced Materials','Energy & Climate']::text[], ARRAY['Characterization & Metrology','Pilot Line / Scale-up','Dry Lab']::text[], 'Collaboration / contract R&D', 'Plasma & ion-implantation surface treatment, sol-gel, electrolysis, materials analysis, process upscaling', 'Materia Nova is a UMONS-founded materials innovation centre offering companies collaborative and contract R&D in surface treatments, analysis/characterization and process scale-up.', 'materianova.be', 'approved'),
  ('BE-011', 'Multitel', 'Multitel', 'Research Institute', 'BE', 'Mons', 50.473, 3.917, ARRAY['Semiconductors & Photonics','Robotics & Automation']::text[], ARRAY['Cleanroom / Nanofab','Characterization & Metrology','Prototyping / Makerspace']::text[], 'Collaboration / contract R&D', '4,200 m2 photonics cleanroom & labs, laser micro-manufacturing platform, optical metrology, fibre/Bragg sensors, THz NDT', 'Multitel, a Walloon-recognised research centre, offers SMEs applied-photonics services from feasibility studies and optical metrology to micro-production, using its photonics cleanroom and laser micro-manufacturing platform.', 'multitel.eu', 'approved'),
  ('BE-012', 'VIB Bio-Incubator Ghent (Bio-Accelerator)', 'VIB', 'Incubator / Accelerator', 'BE', 'Ghent', 51.003, 3.77, ARRAY['Life Sciences & Biotech']::text[], ARRAY['Wet Lab','Biomanufacturing / GMP']::text[], 'Membership / residency', '~6,000 m2 modular wet-lab & office modules, shared services (environmental management, ICT, waste, security)', 'VIB''s Bio-Incubator/Bio-Accelerator at Tech Lane Ghent Science Park rents fully-equipped modular wet labs and offices with shared services to growing biotech and life-science companies.', 'vib.be', 'approved'),
  ('BE-013', 'Bio-Incubator Leuven', 'KU Leuven (LRD)', 'Incubator / Accelerator', 'BE', 'Leuven', 50.861, 4.679, ARRAY['Life Sciences & Biotech']::text[], ARRAY['Wet Lab']::text[], 'Membership / residency', '~14,000 m2 ventilated lab & office space across five buildings, technical/logistical/environmental support', 'KU Leuven''s Bio-Incubator at Arenberg Science Park offers ventilated lab and office space plus technical and logistical support to R&D-intensive life-science companies, across five buildings.', 'bioincubator.be', 'approved'),
  ('BE-014', 'BioVille', 'LRM / UHasselt / POM Limburg', 'Incubator / Accelerator', 'BE', 'Diepenbeek', 50.921, 5.392, ARRAY['Life Sciences & Biotech']::text[], ARRAY['Wet Lab']::text[], 'Membership / residency', 'Office and laboratory facilities with technical and business support, scale-up wing', 'BioVille is a health-and-care incubator at the Diepenbeek health campus providing wet-lab and office space plus business and technical support to biotech, medtech and digital-health startups and scale-ups.', 'bioville.be', 'approved'),
  ('BE-015', 'ESA BIC Belgium', 'ESA / We Are Founders', 'Incubator / Accelerator', 'BE', 'Brussels', 50.846, 4.358, ARRAY['Space & Aerospace']::text[], ARRAY['Prototyping / Makerspace']::text[], 'Program / cohort', '', 'ESA BIC Belgium incubates startups re-using space technology, ESA IP or satellite data, providing equity-free funding plus 12-24 months of coaching across four Belgian locations.', 'space-business.be', 'approved'),
  ('BE-016', 'Materialise Manufacturing', 'Materialise NV', 'Core Facility', 'BE', 'Leuven', 50.8635, 4.678, ARRAY['Advanced Manufacturing','Life Sciences & Biotech']::text[], ARRAY['Prototyping / Makerspace','Pilot Line / Scale-up']::text[], 'Fee-for-service', 'Large single-site additive-manufacturing capacity, online ordering, design & engineering, rapid prototyping and production parts', 'Materialise, headquartered in Leuven, runs a 3D-printing service bureau offering companies fee-for-service rapid prototyping, design/engineering and additive-manufacturing production of parts.', 'materialise.com', 'approved'),
  ('DK-001', 'DTU Nanolab', 'Technical University of Denmark (DTU)', 'Core Facility', 'DK', 'Kongens Lyngby', 55.7855, 12.5232, ARRAY['Semiconductors & Photonics','Quantum','Advanced Materials']::text[], ARRAY['Cleanroom / Nanofab','Characterization & Metrology','Pilot Line / Scale-up']::text[], 'Open user access (proposal)', '1350 m2 class 10-100 cleanroom, lithography, etch, deposition, SEM/TEM, e-beam', 'National open-access nanofabrication and characterization centre (formerly Danchip); external academic and commercial users run their own processes via a frame contract after training, or buy fabrication as a service.', 'nanolab.dtu.dk', 'approved'),
  ('DK-002', 'DTU Biosustain – Biofoundry & Pre-Pilot Plant', 'Novo Nordisk Foundation Center for Biosustainability, DTU', 'Pilot Line / Test Bed', 'DK', 'Kongens Lyngby', 55.7868, 12.521, ARRAY['Life Sciences & Biotech','Advanced Materials']::text[], ARRAY['Biomanufacturing / GMP','Pilot Line / Scale-up','Wet Lab']::text[], 'Collaboration / contract R&D', 'DNA foundry, lab automation, fermentation nL-100 L, pre-pilot downstream processing', 'The Biofoundry and Pre-Pilot Plant take microbial cell-factory and novel-food processes from idea to first prototype; accessible to startups and SMEs through co-financed collaborations and contract projects.', 'biosustain.dtu.dk', 'approved'),
  ('DK-003', 'DTU Skylab', 'Technical University of Denmark (DTU)', 'Incubator / Accelerator', 'DK', 'Kongens Lyngby', 55.7847, 12.5198, ARRAY['Advanced Manufacturing','Life Sciences & Biotech','Energy & Climate']::text[], ARRAY['Prototyping / Makerspace','Dry Lab','Wet Lab']::text[], 'Program / cohort', 'Metal/wood/electronics workshops, 3D printing, laser cutting, chem/bio labs, Developer Hall for large prototypes', 'DTU innovation hub providing startups, students and collaborators with prototyping workshops, wet/dry labs and a large-scale Developer Hall plus coaching and funding programs.', 'skylab.dtu.dk', 'approved'),
  ('DK-004', 'DTU-ESA Antenna Test Facility', 'DTU Space (Technical University of Denmark)', 'Core Facility', 'DK', 'Kongens Lyngby', 55.7889, 12.5256, ARRAY['Space & Aerospace','Semiconductors & Photonics']::text[], ARRAY['Characterization & Metrology']::text[], 'Fee-for-service', 'Spherical near-field antenna range, antennas up to 6.7 m / 300 kg, 0.4-40 GHz', 'Spherical near-field antenna measurement facility operated with ESA that serves as an external reference laboratory; companies and space organisations contract antenna calibration and measurement campaigns.', 'space.dtu.dk', 'approved'),
  ('DK-005', 'BioInnovation Institute (BII)', 'BioInnovation Institute Foundation', 'Incubator / Accelerator', 'DK', 'Copenhagen', 55.7008, 12.561, ARRAY['Life Sciences & Biotech','Quantum']::text[], ARRAY['Wet Lab','Dry Lab']::text[], 'Program / cohort', 'State-of-the-art shared wet labs and offices', 'Life-science incubator whose 12-month Venture Lab program gives admitted startups lab and office space, a convertible loan and mentoring; international startups may join via a Danish entity.', 'bii.dk', 'approved'),
  ('DK-006', 'COBIS – Copenhagen Bio Science Park', 'Symbion / COBIS A/S', 'Incubator / Accelerator', 'DK', 'Copenhagen', 55.6989, 12.5614, ARRAY['Life Sciences & Biotech']::text[], ARRAY['Wet Lab']::text[], 'Membership / residency', 'Configurable class-2 laboratory units, offices, shared facilities', 'Denmark''s largest biotech/life-science science park offering startups and SMEs rentable lab space configurable as class-2 laboratories plus offices on flexible membership terms.', 'cobis.dk', 'approved'),
  ('DK-007', 'QuNorth (Magne quantum computer)', 'QuNorth (EIFO & Novo Nordisk Foundation)', 'Core Facility', 'DK', 'Copenhagen', 55.6995, 12.563, ARRAY['Quantum']::text[], ARRAY['Dry Lab']::text[], 'Program / cohort', 'Level-2 neutral-atom quantum computer (50 logical / 1,200+ physical qubits), Microsoft Azure stack', 'Nordic initiative operating the Magne quantum computer to provide Nordic researchers, startups and industry stable access; early users selected via the QuNorth Flagship program.', 'qunorth.com', 'approved'),
  ('DK-008', 'Danish Technological Institute (DTI)', 'Teknologisk Institut (GTS)', 'Pilot Line / Test Bed', 'DK', 'Taastrup', 55.6543, 12.2861, ARRAY['Advanced Materials','Advanced Manufacturing','Life Sciences & Biotech']::text[], ARRAY['Pilot Line / Scale-up','Prototyping / Makerspace','Characterization & Metrology']::text[], 'Fee-for-service', 'Industrial metal/polymer 3D printing line, biosolutions/biorefinery pilot, materials testing', 'Approved technological-service institute (GTS) selling 3D-printing production, materials development, testing and a biosolutions pilot facility to companies on a fee-for-service and contract basis.', 'dti.dk', 'approved'),
  ('DK-009', 'Odense Robotics StartUp Hub', 'Odense Robotics (at DTI Odense)', 'Incubator / Accelerator', 'DK', 'Odense', 55.368, 10.428, ARRAY['Robotics & Automation','Advanced Manufacturing']::text[], ARRAY['Prototyping / Makerspace','Pilot Line / Scale-up']::text[], 'Program / cohort', '3D printing, vision equipment, robots, mobile platforms, grippers, test space', 'Robotics, automation and drone accelerator in a 3,000 m2 facility at DTI Odense where cohort startups get prototyping/test equipment, robotics experts and up to 24 months of mentoring.', 'odenserobotics.dk', 'approved'),
  ('DK-010', 'Bioneer A/S', 'Bioneer A/S (GTS, DTU subsidiary)', 'Research Institute', 'DK', 'Horsholm', 55.8807, 12.501, ARRAY['Life Sciences & Biotech']::text[], ARRAY['Wet Lab','Biomanufacturing / GMP','Characterization & Metrology']::text[], 'Collaboration / contract R&D', 'Disease/cell models, iPSC & gene editing, recombinant protein and GMP process protein production', 'Not-for-profit GTS contract research/manufacturing organisation providing biotech and pharma companies contract research in cell/molecular biology, disease models and recombinant (incl. GMP) proteins.', 'bioneer.dk', 'approved'),
