  ('DK-014', 'AAU Energy – Battery Systems Test Laboratory', 'Aalborg University (AAU Energy)', 'Core Facility', 'DK', 'Aalborg', 57.015, 9.987, ARRAY['Energy & Climate','Advanced Materials']::text[], ARRAY['Characterization & Metrology','Pilot Line / Scale-up']::text[], 'Collaboration / contract R&D', '5 battery test stations, 20 climatic chambers (-30 to 80 C), EIS analyzers, isothermal calorimeter, BMS emulator', 'State-of-the-art lab for electrical, thermal and lifetime testing of battery cells, packs and BMS that can be used by academia and industry for characterization and lifetime testing.', 'energy.aau.dk', 'approved'),
  ('DK-015', 'ESA BIC Denmark', 'European Space Agency / DTU (lead)', 'Incubator / Accelerator', 'DK', 'Kongens Lyngby', 55.7861, 12.5234, ARRAY['Space & Aerospace']::text[], ARRAY['Prototyping / Makerspace']::text[], 'Program / cohort', 'Technical support, non-equity funding, mentoring; hubs in Lyngby, Aarhus, Aalborg', 'ESA business incubation programme (hubs in Kgs. Lyngby, Aarhus and Aalborg) admitting space-related startups for up to 2 years with funding, technical/business support and network access.', 'spaceventures.dk', 'approved'),
  ('PL-001', 'CEZAMAT Central Laboratory', 'Warsaw University of Technology', 'Core Facility', 'PL', 'Warsaw', 52.1487, 21.008, ARRAY['Semiconductors & Photonics','Life Sciences & Biotech','Advanced Materials']::text[], ARRAY['Cleanroom / Nanofab','Wet Lab','Characterization & Metrology']::text[], 'Fee-for-service', 'Semiconductor & biotech cleanrooms, lithography, deposition, etching, micro/nanofabrication', 'CEZAMAT''s cleanroom network is open to external students, PhD students and entrepreneurs via paid research services or project collaboration; it joined the EuroNanoLab open-access network in 2025.', 'cezamat.pw.edu.pl', 'approved'),
  ('PL-002', 'SOLARIS National Synchrotron Radiation Centre', 'Jagiellonian University', 'Core Facility', 'PL', 'Krakow', 50.029, 19.905, ARRAY['Advanced Materials','Life Sciences & Biotech','Semiconductors & Photonics']::text[], ARRAY['Characterization & Metrology']::text[], 'Open user access (proposal)', 'Synchrotron beamlines (ASTRA, PHELIX, PIRX, POLYX, URANOS, DEMETER), cryo-EM Titan Krios', 'Poland''s national synchrotron runs biannual open calls for proposals; beamtime is allocated by an international panel and is free of charge for non-proprietary research.', 'synchrotron.uj.edu.pl', 'approved'),
  ('PL-003', 'Lukasiewicz – PORT Clean Room & Materials Labs', 'Lukasiewicz Research Network – PORT', 'Research Institute', 'PL', 'Wroclaw', 51.167, 16.94, ARRAY['Advanced Materials','Semiconductors & Photonics','Life Sciences & Biotech']::text[], ARRAY['Cleanroom / Nanofab','Wet Lab','Characterization & Metrology']::text[], 'Collaboration / contract R&D', 'ISO 5/6 cleanroom (600 m2), photolithography, magnetron sputtering, e-beam, PECVD, ICP-RIE; bioimaging, cell biology labs', 'Lukasiewicz-PORT offers commercial microfabrication, materials and bioanalytical services to external companies and research institutions on a quotation basis.', 'port.lukasiewicz.gov.pl', 'approved'),
