  ('LT-001', 'PFI – Prototype Formation and Integration (FTMC Open User Facility)', 'Center for Physical Sciences and Technology (FTMC)', 'Core Facility', 'LT', 'Vilnius', 54.7237, 25.301, ARRAY['Semiconductors & Photonics','Advanced Materials','Quantum']::text[], ARRAY['Cleanroom / Nanofab','Characterization & Metrology','Pilot Line / Scale-up']::text[], 'Fee-for-service', 'ISO5/ISO7 cleanroom, two III-V MBE reactors, magnetron & e-beam sputtering, PECVD, ICP-RIE etching, laser lithography', 'PFI is an ISO 9001 Open User Facility offering external companies fee-for-service access to its III-V semiconductor cleanroom, epitaxy, deposition, etching and lithography via a published service catalogue.', 'pfi.ftmc.lt', 'approved'),
