  ('EE-001', 'Institute of Technology Core Facilities', 'University of Tartu', 'Core Facility', 'EE', 'Tartu', 58.369, 26.696, ARRAY['Life Sciences & Biotech','Advanced Materials','Advanced Manufacturing']::text[], ARRAY['Wet Lab','Characterization & Metrology','Prototyping / Makerspace']::text[], 'Fee-for-service', 'Confocal microscopy, flow cytometry, qPCR, LC-MS/MS proteomics, ABSL3 biosafety lab, equipment fabrication, simulation', 'Five core facilities (Cell Technology, Proteomics, Biosafety ABSL3, Scientific Equipment, Simulation) provide fee-based services to the private sector with published price lists; non-university users register for access.', 'tuit.ut.ee', 'approved'),
  ('EE-002', 'Tartu Observatory Testing & Calibration Centre', 'University of Tartu (Estonian Space Centre)', 'Pilot Line / Test Bed', 'EE', 'Toravere', 58.2647, 26.4654, ARRAY['Space & Aerospace','Advanced Manufacturing']::text[], ARRAY['Characterization & Metrology','Cleanroom / Nanofab','Prototyping / Makerspace']::text[], 'Fee-for-service', 'Thermal-vacuum, vibration & shock, climatic and EMC test rigs; ISO8 cleanroom; optical calibration rooms; ESD-safe areas', 'An ISO 17025-accredited testing and calibration centre where companies test nanosatellites, subsystems and equipment under space-relevant environmental conditions and calibrate optical devices.', 'to.ee', 'approved'),
  ('EE-003', 'Mektory Innovation & Business Centre', 'Tallinn University of Technology (TalTech)', 'Incubator / Accelerator', 'EE', 'Tallinn', 59.3955, 24.661, ARRAY['Advanced Manufacturing','Robotics & Automation']::text[], ARRAY['Prototyping / Makerspace']::text[], 'Collaboration / contract R&D', 'Prototyping lab, workshops and demo facilities for academia-industry R&D and technology transfer', 'Mektory connects students, university labs and external SMEs/corporates for technology transfer and R&D projects, and its prototyping lab and facilities are open to companies for collaboration.', 'taltech.ee', 'approved'),
