  ('LV-001', 'Materize – ISSP UL Open Labs & Cleanroom', 'Institute of Solid State Physics, University of Latvia (ISSP UL)', 'Core Facility', 'LV', 'Riga', 56.943, 24.174, ARRAY['Advanced Materials','Semiconductors & Photonics','Energy & Climate']::text[], ARRAY['Cleanroom / Nanofab','Characterization & Metrology','Pilot Line / Scale-up']::text[], 'Open user access (proposal)', '680 m2 ISO 7-8 cleanroom, e-beam & optical lithography, ALD/PVD/CVD thin-film deposition, spectroscopy, microscopy', 'ISSP UL runs Open Labs available to researchers and industry, and its Materize platform offers companies cleanroom-based prototyping, thin-film and characterization services (the only classified cleanroom in Latvia).', 'cfi.lu.lv', 'approved'),
  ('LV-002', 'Genome Centre & Core Facilities', 'Latvian Biomedical Research and Study Centre (BMC)', 'Core Facility', 'LV', 'Riga', 56.946, 24.101, ARRAY['Life Sciences & Biotech']::text[], ARRAY['Wet Lab','Characterization & Metrology']::text[], 'Fee-for-service', 'Genome Centre (NGS/sequencing & genotyping), cell culture facility, animal core facility, bioinformatics unit', 'Latvia''s leading molecular-biology institute offers its Genome Centre and other core facilities as fee-based services and consultations to local and international clients across biotech and healthcare.', 'biomed.lu.lv', 'approved'),
